export const BUILDINGS = housingData.map((entry) => ({
  name: entry.buildingName,
  group: entry.campusGroup,
  address: entry.address,
  area: "",
  layouts: [...entry.layouts],
}));

export const LARGE_STYLE_RESIDENCES_GROUP = "Large Traditional-Style Residences";

export const LARGE_STYLE_AREA_BY_BUILDING = {
  "Rich Hall": "West Campus",
  "Claflin Hall": "West Campus",
  "Sleeper Hall": "West Campus",
  "1019 Commonwealth Avenue": "West Campus",
  "Warren Towers": "Central Campus",
  "Danielsen Hall": "East Campus",
  "610 Beacon Street": "East Campus",
  "575 Commonwealth Avenue (HoJo)": "East Campus",
  "The Towers": "East Campus",
  "Kilachand Hall": "East Campus",
};

export const LARGE_STYLE_AREAS = ["West Campus", "Central Campus", "East Campus"];

BUILDINGS.forEach((building) => {
  if (building.group === LARGE_STYLE_RESIDENCES_GROUP) {
    building.area = LARGE_STYLE_AREA_BY_BUILDING[building.name] || "";
  }
});

export const CAMPUS_GROUPS = [...new Set(BUILDINGS.map((building) => building.group))];

export const ADDRESSES_BY_GROUP = BUILDINGS.reduce((acc, building) => {
  if (!acc[building.group]) acc[building.group] = [];
  acc[building.group].push({
    name: building.name,
    address: building.address,
    area: building.area,
    layouts: building.layouts,
  });
  return acc;
}, {});

export const LAYOUTS_BY_ADDRESS = Object.fromEntries(
  BUILDINGS.map(({ address, layouts }) => [address, layouts])
);

/**
 * Split a layout string like "Traditional Double" into:
 * { roomType: "Traditional", occupancy: "Double" }
 */
export function parseLayout(layout) {
  if (!layout) return { roomType: "", occupancy: "" };

  const words = layout.trim().split(" ");
  return {
    occupancy: words[words.length - 1],
    roomType: words.slice(0, -1).join(" "),
  };
}

export const LAYOUTS_BY_BUILDING = Object.fromEntries(
  BUILDINGS.map(({ name, layouts }) => [name, layouts])
);

export const BUILDINGS_BY_GROUP = BUILDINGS.reduce((acc, building) => {
  if (!acc[building.group]) acc[building.group] = [];
  acc[building.group].push(building.name);
  return acc;
}, {});

export const ROOM_TYPES = [
  ...new Set(
    BUILDINGS.flatMap((building) =>
      building.layouts.map((layout) => parseLayout(layout).roomType)
    )
  ),
];

export const OCCUPANCIES = [
  ...new Set(
    BUILDINGS.flatMap((building) =>
      building.layouts.map((layout) => parseLayout(layout).occupancy)
    )
  ),
];

export function getLayoutsForBuilding(buildingName) {
  return LAYOUTS_BY_BUILDING[buildingName] || [];
}

export function getLayoutsForAddress(address) {
  return LAYOUTS_BY_ADDRESS[address] || [];
}

export function getAllBuildings() {
  return BUILDINGS.map((building) => building.name);
}

export function getBuildingsForGroup(groupName) {
  return BUILDINGS.filter((building) => building.group === groupName);
}

export function getAddressesForGroup(groupName) {
  return ADDRESSES_BY_GROUP[groupName] || [];
}

export function getLayoutsForGroups(groupNames = []) {
  const selectedGroups = groupNames.length ? groupNames : CAMPUS_GROUPS;
  return [
    ...new Set(
      selectedGroups.flatMap((groupName) =>
        getAddressesForGroup(groupName).flatMap((entry) => entry.layouts)
      )
    ),
  ];
}

export function getLargeResidenceAreas() {
  return [...LARGE_STYLE_AREAS];
}

export function getLargeResidenceBuildings(selectedAreas = []) {
  const largeBuildings = BUILDINGS.filter((building) => building.group === LARGE_STYLE_RESIDENCES_GROUP);
  if (!selectedAreas.length) return [];
  return largeBuildings.filter((building) => selectedAreas.includes(building.area));
}

export function getLayoutsForLargeResidenceSelections(selectedAreas = [], selectedBuildingNames = []) {
  const buildings = getLargeResidenceBuildings(selectedAreas)
    .filter((building) => selectedBuildingNames.includes(building.name));
  return [...new Set(buildings.flatMap((building) => building.layouts))];
}

export function getLayoutsForBuildingNames(buildingNames = []) {
  return [...new Set(
    BUILDINGS
      .filter((b) => buildingNames.includes(b.name))
      .flatMap((b) => b.layouts)
  )];
}

export function getBuildingByAddress(address) {
  return BUILDINGS.find((building) => building.address === address) || null;
}

export function getBuildingByName(buildingName) {
  return BUILDINGS.find((building) => building.name === buildingName) || null;
}

export function getBuildingsWithApartmentLayouts() {
  return BUILDINGS.filter((building) =>
    building.layouts.some((layout) => layout.startsWith("Apartment"))
  ).map((building) => building.name);
}

export function getBuildingsWithOccupancy(occupancy) {
  return BUILDINGS.filter((building) =>
    building.layouts.some((layout) => layout.endsWith(occupancy))
  ).map((building) => building.name);
}

export function getCampusGroupsWithOccupancy(occupancy) {
  const buildingsWithOccupancy = getBuildingsWithOccupancy(occupancy);
  return [...new Set(
    BUILDINGS.filter((building) => buildingsWithOccupancy.includes(building.name))
      .map((building) => building.group)
  )];
}